package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.uoe;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.Map;

import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.uoe.cost.SimpleUoeCostModel;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.uoe.cost.UoeCostContext;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.uoe.cost.UoeCostEstimate;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.uoe.stats.UoeCardEstimate;
import org.eclipse.rdf4j.query.parser.QueryParserUtil;
import org.junit.jupiter.api.Test;

class SimpleUoeCostModelTest {

	@Test
	void computesPredictedMillisAndRiskFromRowsAndConfidence() {
		TupleExpr tupleExpr = parseTupleExpr("SELECT * WHERE { ?s ?p ?o }");
		UoeCardEstimate estimate = new UoeCardEstimate(100.0d, 0.75d, 0.75d, Map.of(), Map.of());
		UoeCostContext context = new UoeCostContext(estimate, 2.0d, 0.5d, 10.0d);

		UoeCostEstimate cost = new SimpleUoeCostModel().cost(tupleExpr, context);

		assertThat(cost.getPredictedMillis()).isEqualTo(54.5d);
		assertThat(cost.getRisk()).isEqualTo(0.25d);
		assertThat(cost.getBreakdown()).containsEntry("startupMillis", 2.0d);
		assertThat(cost.getBreakdown()).containsEntry("rowMillis", 50.0d);
		assertThat(cost.getBreakdown()).containsEntry("uncertaintyMillis", 2.5d);
	}

	private static TupleExpr parseTupleExpr(String query) {
		return QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, query, null).getTupleExpr();
	}
}
